# 1 Butter Chicken
recipes.append({"slug":"butter-chicken","version":1,"title":"Butter Chicken (Murgh Makhani)","category":"Indian","description":"The iconic creamy tomato-based curry that conquered the world. Tender chicken simmered in a velvety sauce of butter, cream, and aromatic spices.","hero_image_url":"https://images.unsplash.com/photo-1603894584373-5ac82b2ae398?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixlib=rb-4.1.0&q=80&w=1080","meta_title":"Butter Chicken Recipe (Murgh Makhani)","meta_description":"Creamy butter chicken with tender marinated chicken in a velvety tomato-butter sauce. The ultimate Indian comfort food.","keywords":j(["butter chicken","murgh makhani","indian curry","creamy chicken","indian food"]),"ingredients":j([{"name":"Chicken thighs (boneless)","quantity":"800","unit":"g"},{"name":"Plain yogurt","quantity":"150","unit":"g"},{"name":"Kashmiri red chilli powder","quantity":"2","unit":"tsp"},{"name":"Garam masala","quantity":"2","unit":"tsp"},{"name":"Ginger-garlic paste","quantity":"2","unit":"tbsp"},{"name":"Butter","quantity":"60","unit":"g"},{"name":"Onion","quantity":"2","unit":"large"},{"name":"Tomatoes","quantity":"500","unit":"g"},{"name":"Cashews","quantity":"30","unit":"g"},{"name":"Heavy cream","quantity":"150","unit":"ml"},{"name":"Kasuri methi","quantity":"1","unit":"tbsp"}]),"steps":j([{"order":1,"instruction":"Marinate chicken in yogurt, lemon juice, chilli powder, garam masala, and ginger-garlic paste for 2 hours."},{"order":2,"instruction":"Grill or pan-fry marinated chicken on high heat until charred. Set aside."},{"order":3,"instruction":"Melt butter. Saute onions until golden. Add ginger-garlic paste and cook 2 minutes."},{"order":4,"instruction":"Add tomatoes and cashews. Cook 15 minutes. Blend smooth and strain."},{"order":5,"instruction":"Return sauce to pan. Add spices and simmer 10 minutes."},{"order":6,"instruction":"Add chicken, cream, and kasuri methi. Simmer 5 minutes. Finish with butter."}]),"nutrition":j({"calories":420,"protein_g":35,"carbs_g":14,"fat_g":26,"serving_size":"1 serving"}),"tips":j(["Kashmiri chilli gives vibrant colour without too much heat.","Straining the sauce gives a restaurant-smooth texture.","Kasuri methi is non-negotiable for authentic flavour.","Char the chicken for smoky depth."]),"youtube_query":"butter chicken recipe murgh makhani","youtube_video_id":"a03U45jFxOI","prep_time":"20 minutes (plus 2 hours marinating)","cook_time":"40 minutes","total_time":"3 hours","difficulty":"Medium","servings":"4 servings","related_recipes":j(["chicken-tikka-masala","dal-makhani","palak-paneer"]),"published":1})

# 2 Dal Makhani
recipes.append({"slug":"dal-makhani","version":1,"title":"Dal Makhani","category":"Indian","description":"The crown jewel of Punjabi cuisine. Whole black lentils and kidney beans slow-cooked with butter and cream into a silky, smoky, deeply flavoured dal.","hero_image_url":"https://images.unsplash.com/photo-1546833999-b9f581a1996d?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixlib=rb-4.1.0&q=80&w=1080","meta_title":"Dal Makhani Recipe - Creamy Black Lentil Curry","meta_description":"Authentic dal makhani with whole black lentils slow-cooked with butter and cream. Rich, smoky Punjabi comfort food.","keywords":j(["dal makhani","black lentil curry","punjabi dal","indian lentils","vegetarian indian"]),"ingredients":j([{"name":"Whole black lentils (urad dal)","quantity":"250","unit":"g"},{"name":"Red kidney beans (rajma)","quantity":"50","unit":"g"},{"name":"Butter","quantity":"80","unit":"g"},{"name":"Onion","quantity":"1","unit":"large"},{"name":"Tomato puree","quantity":"200","unit":"ml"},{"name":"Ginger-garlic paste","quantity":"2","unit":"tbsp"},{"name":"Red chilli powder","quantity":"1","unit":"tsp"},{"name":"Garam masala","quantity":"1","unit":"tsp"},{"name":"Heavy cream","quantity":"100","unit":"ml"},{"name":"Kasuri methi","quantity":"1","unit":"tsp"}]),"steps":j([{"order":1,"instruction":"Soak lentils and kidney beans overnight. Pressure cook with salt for 45 minutes until completely soft."},{"order":2,"instruction":"Mash about a quarter of the lentils to thicken the dal."},{"order":3,"instruction":"Melt butter. Saute onions until deep golden. Add ginger-garlic paste and cook 2 minutes."},{"order":4,"instruction":"Add tomato puree, chilli powder, and garam masala. Cook until oil separates, about 10 minutes."},{"order":5,"instruction":"Add cooked lentils to the masala. Simmer on very low heat for at least 1 hour, stirring often."},{"order":6,"instruction":"Stir in cream and kasuri methi. Simmer 10 more minutes. Finish with a generous knob of butter."}]),"nutrition":j({"calories":380,"protein_g":16,"carbs_g":42,"fat_g":18,"serving_size":"1 serving"}),"tips":j(["The longer it simmers, the better it tastes.","Mashing some lentils creates a naturally thick texture.","A charcoal smoke (dhungar method) adds authentic tandoor flavour.","Leftovers taste even better the next day."]),"youtube_query":"dal makhani recipe authentic","youtube_video_id":"Yw5UNqFBCow","prep_time":"10 minutes (plus overnight soaking)","cook_time":"2 hours","total_time":"3 hours","difficulty":"Easy","servings":"4 servings","related_recipes":j(["butter-chicken","palak-paneer","rajma-chawal"]),"published":1})

# 3 Palak Paneer
recipes.append({"slug":"palak-paneer","version":1,"title":"Palak Paneer","category":"Indian","description":"Soft cubes of fresh cottage cheese nestled in a vibrant, velvety spinach gravy spiced with cumin, ginger, and garam masala. A beloved North Indian vegetarian classic.","hero_image_url":"https://images.unsplash.com/photo-1601050690597-df0568f70950?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixlib=rb-4.1.0&q=80&w=1080","meta_title":"Palak Paneer Recipe - Spinach and Cottage Cheese Curry","meta_description":"Vibrant palak paneer with soft paneer cubes in a smooth, spiced spinach gravy. Classic North Indian vegetarian curry.","keywords":j(["palak paneer","spinach paneer","indian vegetarian","paneer curry","north indian"]),"ingredients":j([{"name":"Fresh spinach","quantity":"500","unit":"g"},{"name":"Paneer","quantity":"300","unit":"g"},{"name":"Onion","quantity":"1","unit":"large"},{"name":"Tomato","quantity":"2","unit":"medium"},{"name":"Ginger-garlic paste","quantity":"1","unit":"tbsp"},{"name":"Green chillies","quantity":"2","unit":"whole"},{"name":"Cumin seeds","quantity":"1","unit":"tsp"},{"name":"Garam masala","quantity":"1","unit":"tsp"},{"name":"Cream","quantity":"3","unit":"tbsp"},{"name":"Ghee","quantity":"2","unit":"tbsp"}]),"steps":j([{"order":1,"instruction":"Blanch spinach in boiling water for 2 minutes. Transfer to ice water to preserve colour. Blend with green chillies to a smooth puree."},{"order":2,"instruction":"Pan-fry paneer cubes in oil until golden on all sides. Set aside."},{"order":3,"instruction":"Heat ghee. Add cumin seeds and let them splutter. Add onions and cook until golden."},{"order":4,"instruction":"Add ginger-garlic paste and tomatoes. Cook until tomatoes are soft and oil separates."},{"order":5,"instruction":"Add spinach puree and garam masala. Simmer 5 minutes. Add fried paneer cubes."},{"order":6,"instruction":"Stir in cream. Simmer 2 minutes. Adjust salt and serve with naan or rice."}]),"nutrition":j({"calories":320,"protein_g":18,"carbs_g":12,"fat_g":22,"serving_size":"1 serving"}),"tips":j(["Ice water after blanching keeps the spinach brilliantly green.","Do not overcook the spinach puree or it loses its colour.","Frying paneer first gives it a golden crust that holds up in the gravy.","A pinch of nutmeg in the spinach puree adds subtle warmth."]),"youtube_query":"palak paneer recipe restaurant style","youtube_video_id":"SP-Iqj5QLOU","prep_time":"15 minutes","cook_time":"25 minutes","total_time":"40 minutes","difficulty":"Easy","servings":"4 servings","related_recipes":j(["butter-chicken","paneer-tikka","dal-makhani"]),"published":1})

# 4 Chicken Biryani
recipes.append({"slug":"chicken-biryani","version":1,"title":"Chicken Biryani","category":"Indian","description":"The king of Indian rice dishes. Fragrant basmati rice layered with spiced marinated chicken and slow-cooked (dum) to perfection. Every grain infused with saffron, caramelised onions, and whole spices.","hero_image_url":"https://images.unsplash.com/photo-1563379091339-03246963d96c?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixlib=rb-4.1.0&q=80&w=1080","meta_title":"Chicken Biryani Recipe - Authentic Dum Biryani","meta_description":"Authentic chicken biryani with fragrant basmati rice, marinated chicken, and saffron. Slow-cooked dum style for maximum flavour.","keywords":j(["chicken biryani","dum biryani","indian rice","hyderabadi biryani","basmati rice"]),"ingredients":j([{"name":"Basmati rice","quantity":"400","unit":"g"},{"name":"Chicken (bone-in)","quantity":"1","unit":"kg"},{"name":"Plain yogurt","quantity":"200","unit":"g"},{"name":"Onions","quantity":"3","unit":"large"},{"name":"Ginger-garlic paste","quantity":"3","unit":"tbsp"},{"name":"Biryani masala","quantity":"3","unit":"tbsp"},{"name":"Saffron","quantity":"1","unit":"pinch"},{"name":"Warm milk","quantity":"4","unit":"tbsp"},{"name":"Ghee","quantity":"4","unit":"tbsp"},{"name":"Whole spices (bay leaf, cardamom, cloves, cinnamon)","quantity":"1","unit":"set"},{"name":"Fresh mint leaves","quantity":"1","unit":"handful"},{"name":"Fresh coriander","quantity":"1","unit":"handful"}]),"steps":j([{"order":1,"instruction":"Marinate chicken in yogurt, ginger-garlic paste, biryani masala, and salt for at least 2 hours."},{"order":2,"instruction":"Fry sliced onions in oil until deep golden and crispy (birista). Drain on paper towels."},{"order":3,"instruction":"Soak saffron in warm milk. Parboil rice with whole spices and salt until 70% cooked. Drain."},{"order":4,"instruction":"In a heavy pot, layer marinated chicken at the bottom. Top with half the rice, fried onions, mint, and coriander."},{"order":5,"instruction":"Add remaining rice. Drizzle saffron milk and ghee over the top. Seal the pot with foil and a tight lid."},{"order":6,"instruction":"Cook on high heat 5 minutes, then reduce to lowest heat for 30 minutes (dum). Rest 10 minutes before opening."}]),"nutrition":j({"calories":580,"protein_g":38,"carbs_g":62,"fat_g":18,"serving_size":"1 serving"}),"tips":j(["Crispy fried onions (birista) are the soul of biryani.","Parboiling rice to exactly 70% is critical.","Sealing the pot traps steam for the dum cooking process.","Use a heavy-bottomed pot or place a tawa under to prevent burning."]),"youtube_query":"chicken biryani recipe dum style","youtube_video_id":"fd2b5oBFMxc","prep_time":"30 minutes (plus 2 hours marinating)","cook_time":"1 hour","total_time":"3 hours 30 minutes","difficulty":"Hard","servings":"5 servings","related_recipes":j(["butter-chicken","mutton-biryani","chicken-tikka-masala"]),"published":1})

# 5 Paneer Tikka
recipes.append({"slug":"paneer-tikka","version":1,"title":"Paneer Tikka","category":"Indian","description":"Chunks of paneer and vegetables marinated in a spiced yogurt coating and grilled until charred and smoky. The ultimate Indian vegetarian starter, packed with tandoor flavour.","hero_image_url":"https://images.unsplash.com/photo-1567188040759-fb8a883dc6d8?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixlib=rb-4.1.0&q=80&w=1080","meta_title":"Paneer Tikka Recipe - Grilled Spiced Cottage Cheese","meta_description":"Smoky, charred paneer tikka with spiced yogurt marinade. Perfect Indian vegetarian starter ready in 30 minutes.","keywords":j(["paneer tikka","indian starter","grilled paneer","vegetarian bbq","tandoori paneer"]),"ingredients":j([{"name":"Paneer","quantity":"400","unit":"g"},{"name":"Bell peppers (mixed)","quantity":"2","unit":"whole"},{"name":"Onion","quantity":"1","unit":"large"},{"name":"Thick yogurt","quantity":"150","unit":"g"},{"name":"Ginger-garlic paste","quantity":"1","unit":"tbsp"},{"name":"Kashmiri chilli powder","quantity":"2","unit":"tsp"},{"name":"Cumin powder","quantity":"1","unit":"tsp"},{"name":"Chaat masala","quantity":"1","unit":"tsp"},{"name":"Lemon juice","quantity":"2","unit":"tbsp"},{"name":"Oil","quantity":"2","unit":"tbsp"}]),"steps":j([{"order":1,"instruction":"Cut paneer into 2-inch cubes. Cut peppers and onion into similar-sized pieces."},{"order":2,"instruction":"Mix yogurt with ginger-garlic paste, all spices, lemon juice, oil, and salt to make the marinade."},{"order":3,"instruction":"Coat paneer and vegetables in the marinade. Rest for at least 1 hour."},{"order":4,"instruction":"Thread onto skewers alternating paneer, pepper, and onion."},{"order":5,"instruction":"Grill on a hot grill pan or under a broiler for 3-4 minutes per side until charred."},{"order":6,"instruction":"Sprinkle with chaat masala and serve with mint chutney and sliced onion rings."}]),"nutrition":j({"calories":280,"protein_g":16,"carbs_g":10,"fat_g":20,"serving_size":"1 serving"}),"tips":j(["Hang yogurt in muslin cloth to remove excess water for a better coating.","High heat is essential for the charred, smoky flavour.","Baste with butter while grilling for extra richness.","Chaat masala sprinkled at the end adds a tangy punch."]),"youtube_query":"paneer tikka recipe on tawa","youtube_video_id":"Yw5UNqFBCow","prep_time":"15 minutes (plus 1 hour marinating)","cook_time":"15 minutes","total_time":"1 hour 30 minutes","difficulty":"Easy","servings":"4 servings","related_recipes":j(["palak-paneer","chicken-tikka-masala","tandoori-chicken"]),"published":1})

# 6 Chole Bhature
recipes.append({"slug":"chole-bhature","version":1,"title":"Chole Bhature","category":"Indian","description":"A legendary Punjabi street food combo. Spicy, tangy chickpea curry (chole) served with pillowy deep-fried bread (bhature). Bold, hearty, and utterly addictive.","hero_image_url":"https://images.unsplash.com/photo-1626132647523-66c3f4942d4b?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixlib=rb-4.1.0&q=80&w=1080","meta_title":"Chole Bhature Recipe - Spicy Chickpea Curry with Fried Bread","meta_description":"Classic Punjabi chole bhature with spicy chickpea curry and fluffy deep-fried bhature. The ultimate Indian street food combo.","keywords":j(["chole bhature","chickpea curry","punjabi street food","chole masala","indian breakfast"]),"ingredients":j([{"name":"Chickpeas (dried)","quantity":"250","unit":"g"},{"name":"Onions","quantity":"2","unit":"large"},{"name":"Tomatoes","quantity":"3","unit":"medium"},{"name":"Ginger-garlic paste","quantity":"2","unit":"tbsp"},{"name":"Chole masala","quantity":"2","unit":"tbsp"},{"name":"Amchur (dry mango powder)","quantity":"1","unit":"tsp"},{"name":"Tea bag","quantity":"1","unit":"whole"},{"name":"All-purpose flour (maida)","quantity":"300","unit":"g"},{"name":"Semolina (sooji)","quantity":"2","unit":"tbsp"},{"name":"Plain yogurt","quantity":"100","unit":"g"},{"name":"Oil for deep frying","quantity":"500","unit":"ml"}]),"steps":j([{"order":1,"instruction":"Soak chickpeas overnight. Pressure cook with a tea bag (for dark colour) and salt for 20 minutes. Discard tea bag."},{"order":2,"instruction":"Make bhature dough: mix flour, semolina, yogurt, salt, and a pinch of baking soda. Knead to a soft dough. Rest 2 hours."},{"order":3,"instruction":"Saute onions until deep brown. Add ginger-garlic paste and tomatoes. Cook until oil separates."},{"order":4,"instruction":"Add chole masala, amchur, and salt. Add cooked chickpeas with some cooking water. Simmer 20 minutes, mashing some chickpeas."},{"order":5,"instruction":"Roll bhature dough into oval shapes. Deep fry in hot oil until puffed and golden."},{"order":6,"instruction":"Serve hot chole with bhature, sliced onion, green chutney, and a wedge of lemon."}]),"nutrition":j({"calories":620,"protein_g":18,"carbs_g":82,"fat_g":24,"serving_size":"1 serving"}),"tips":j(["A tea bag while cooking chickpeas gives them a beautiful dark colour.","Resting the bhature dough is essential for soft, puffed bread.","Amchur (dry mango powder) gives chole its signature tangy flavour.","Fry bhature in very hot oil so they puff up immediately."]),"youtube_query":"chole bhature recipe punjabi","youtube_video_id":"Yw5UNqFBCow","prep_time":"20 minutes (plus overnight soaking and 2 hours dough rest)","cook_time":"45 minutes","total_time":"3 hours","difficulty":"Medium","servings":"4 servings","related_recipes":j(["rajma-chawal","dal-makhani","aloo-paratha"]),"published":1})

# 7 Aloo Paratha
recipes.append({"slug":"aloo-paratha","version":1,"title":"Aloo Paratha","category":"Indian","description":"Flaky whole wheat flatbread stuffed with a spiced mashed potato filling, cooked on a tawa with generous amounts of butter or ghee. The quintessential Punjabi breakfast.","hero_image_url":"https://images.unsplash.com/photo-1565557623262-b51c2513a641?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixlib=rb-4.1.0&q=80&w=1080","meta_title":"Aloo Paratha Recipe - Stuffed Potato Flatbread","meta_description":"Crispy, flaky aloo paratha with spiced potato filling. Classic Punjabi breakfast served with yogurt and pickle.","keywords":j(["aloo paratha","potato flatbread","punjabi breakfast","stuffed paratha","indian bread"]),"ingredients":j([{"name":"Whole wheat flour (atta)","quantity":"300","unit":"g"},{"name":"Potatoes (boiled)","quantity":"400","unit":"g"},{"name":"Green chillies (finely chopped)","quantity":"2","unit":"whole"},{"name":"Fresh coriander","quantity":"2","unit":"tbsp"},{"name":"Cumin seeds","quantity":"1","unit":"tsp"},{"name":"Amchur (dry mango powder)","quantity":"0.5","unit":"tsp"},{"name":"Garam masala","quantity":"0.5","unit":"tsp"},{"name":"Butter or ghee","quantity":"4","unit":"tbsp"},{"name":"Salt","quantity":"1","unit":"tsp"}]),"steps":j([{"order":1,"instruction":"Make dough: mix flour, salt, and water. Knead to a soft, smooth dough. Rest 20 minutes."},{"order":2,"instruction":"Mash boiled potatoes. Mix with green chillies, coriander, cumin, amchur, garam masala, and salt."},{"order":3,"instruction":"Divide dough into balls. Roll each into a small circle. Place a ball of potato filling in the centre."},{"order":4,"instruction":"Bring the dough edges together to seal the filling. Gently roll out into a flat circle without breaking."},{"order":5,"instruction":"Cook on a hot tawa (griddle) for 2 minutes per side until golden spots appear."},{"order":6,"instruction":"Apply generous butter or ghee on both sides. Serve hot with yogurt, pickle, and a knob of butter."}]),"nutrition":j({"calories":340,"protein_g":8,"carbs_g":52,"fat_g":12,"serving_size":"1 paratha"}),"tips":j(["Ensure the potato filling is completely dry - excess moisture tears the dough.","Roll gently and evenly to avoid the filling breaking through.","A well-seasoned cast iron tawa gives the best results.","Serve immediately - parathas lose their crispness as they cool."]),"youtube_query":"aloo paratha recipe punjabi style","youtube_video_id":"Yw5UNqFBCow","prep_time":"20 minutes","cook_time":"30 minutes","total_time":"50 minutes","difficulty":"Medium","servings":"6 parathas","related_recipes":j(["chole-bhature","rajma-chawal","dal-makhani"]),"published":1})

# 8 Rajma Chawal
recipes.append({"slug":"rajma-chawal","version":1,"title":"Rajma Chawal","category":"Indian","description":"Red kidney beans slow-cooked in a thick, spiced tomato-onion gravy, served over steamed basmati rice. The ultimate North Indian comfort food - simple, hearty, and deeply satisfying.","hero_image_url":"https://images.unsplash.com/photo-1546833999-b9f581a1996d?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixlib=rb-4.1.0&q=80&w=1080","meta_title":"Rajma Chawal Recipe - Red Kidney Bean Curry with Rice","meta_description":"Hearty rajma chawal with red kidney beans in a thick spiced gravy served over basmati rice. Classic North Indian comfort food.","keywords":j(["rajma chawal","kidney bean curry","north indian","rajma recipe","indian comfort food"]),"ingredients":j([{"name":"Red kidney beans (dried)","quantity":"250","unit":"g"},{"name":"Onions","quantity":"2","unit":"large"},{"name":"Tomatoes","quantity":"3","unit":"medium"},{"name":"Ginger-garlic paste","quantity":"2","unit":"tbsp"},{"name":"Rajma masala","quantity":"2","unit":"tsp"},{"name":"Cumin seeds","quantity":"1","unit":"tsp"},{"name":"Coriander powder","quantity":"1","unit":"tsp"},{"name":"Red chilli powder","quantity":"1","unit":"tsp"},{"name":"Basmati rice","quantity":"300","unit":"g"},{"name":"Oil","quantity":"3","unit":"tbsp"}]),"steps":j([{"order":1,"instruction":"Soak kidney beans overnight. Pressure cook with salt for 20-25 minutes until completely soft."},{"order":2,"instruction":"Heat oil. Add cumin seeds. Once they splutter, add onions and cook until deep golden."},{"order":3,"instruction":"Add ginger-garlic paste and cook 2 minutes. Add tomatoes and cook until oil separates."},{"order":4,"instruction":"Add all spices and cook 2 minutes. Add cooked kidney beans with their cooking liquid."},{"order":5,"instruction":"Simmer on medium heat for 20 minutes, mashing some beans to thicken the gravy."},{"order":6,"instruction":"Cook basmati rice separately. Serve rajma over rice with a dollop of butter and fresh coriander."}]),"nutrition":j({"calories":420,"protein_g":18,"carbs_g":68,"fat_g":10,"serving_size":"1 serving"}),"tips":j(["Never skip soaking - it reduces cooking time and improves digestibility.","Mashing some beans against the pot creates a naturally thick gravy.","A dollop of butter on top when serving is traditional and delicious.","Rajma tastes even better the next day as the flavours deepen."]),"youtube_query":"rajma chawal recipe dhaba style","youtube_video_id":"Yw5UNqFBCow","prep_time":"10 minutes (plus overnight soaking)","cook_time":"45 minutes","total_time":"1 hour","difficulty":"Easy","servings":"4 servings","related_recipes":j(["dal-makhani","chole-bhature","aloo-paratha"]),"published":1})

# 9 Tandoori Chicken
recipes.append({"slug":"tandoori-chicken","version":1,"title":"Tandoori Chicken","category":"Indian","description":"Chicken marinated in yogurt and a bold blend of spices, then roasted at high heat until charred and smoky. The original Indian grilled chicken - fiery red, juicy inside, and irresistibly smoky.","hero_image_url":"https://images.unsplash.com/photo-1599487488170-d11ec9c172f0?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixlib=rb-4.1.0&q=80&w=1080","meta_title":"Tandoori Chicken Recipe - Smoky Spiced Grilled Chicken","meta_description":"Authentic tandoori chicken with yogurt marinade and bold spices. Smoky, charred, and juicy - ready in under 1 hour.","keywords":j(["tandoori chicken","indian grilled chicken","spiced chicken","tandoor","indian bbq"]),"ingredients":j([{"name":"Chicken (bone-in pieces)","quantity":"1","unit":"kg"},{"name":"Plain yogurt","quantity":"200","unit":"g"},{"name":"Kashmiri chilli powder","quantity":"2","unit":"tsp"},{"name":"Garam masala","quantity":"1","unit":"tsp"},{"name":"Cumin powder","quantity":"1","unit":"tsp"},{"name":"Coriander powder","quantity":"1","unit":"tsp"},{"name":"Ginger-garlic paste","quantity":"2","unit":"tbsp"},{"name":"Lemon juice","quantity":"3","unit":"tbsp"},{"name":"Oil","quantity":"2","unit":"tbsp"}]),"steps":j([{"order":1,"instruction":"Score the chicken pieces deeply with a knife so the marinade penetrates."},{"order":2,"instruction":"Mix all marinade ingredients. Coat chicken thoroughly. Marinate for at least 4 hours, preferably overnight."},{"order":3,"instruction":"Preheat oven to 240C (or use a grill/BBQ). Place chicken on a wire rack over a baking tray."},{"order":4,"instruction":"Roast for 20-25 minutes, turning once, until charred in spots and cooked through."},{"order":5,"instruction":"For extra smokiness, hold a piece of burning charcoal in foil over the chicken and drizzle with ghee. Cover for 2 minutes."},{"order":6,"instruction":"Serve with sliced onion rings, lemon wedges, mint chutney, and naan."}]),"nutrition":j({"calories":310,"protein_g":38,"carbs_g":6,"fat_g":14,"serving_size":"1 serving"}),"tips":j(["Deep scoring is essential for the marinade to reach the bone.","Overnight marinating gives the most flavour.","The charcoal smoke trick (dhungar) replicates authentic tandoor smokiness.","Kashmiri chilli gives the iconic red colour without excessive heat."]),"youtube_query":"tandoori chicken recipe oven","youtube_video_id":"Yw5UNqFBCow","prep_time":"15 minutes (plus 4 hours marinating)","cook_time":"25 minutes","total_time":"4 hours 40 minutes","difficulty":"Easy","servings":"4 servings","related_recipes":j(["butter-chicken","paneer-tikka","chicken-biryani"]),"published":1})

# 10 Masala Dosa
recipes.append({"slug":"masala-dosa","version":1,"title":"Masala Dosa","category":"Indian","description":"A crispy, paper-thin fermented rice and lentil crepe filled with a spiced potato masala. South India's most iconic dish, served with coconut chutney and sambar.","hero_image_url":"https://images.unsplash.com/photo-1589301760014-d929f3979dbc?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixlib=rb-4.1.0&q=80&w=1080","meta_title":"Masala Dosa Recipe - Crispy South Indian Crepe","meta_description":"Crispy masala dosa with spiced potato filling. Authentic South Indian recipe with fermented batter and coconut chutney.","keywords":j(["masala dosa","south indian","dosa recipe","crispy dosa","indian breakfast"]),"ingredients":j([{"name":"Parboiled rice","quantity":"300","unit":"g"},{"name":"Urad dal (split black lentils)","quantity":"100","unit":"g"},{"name":"Fenugreek seeds","quantity":"0.5","unit":"tsp"},{"name":"Potatoes (boiled)","quantity":"400","unit":"g"},{"name":"Onion","quantity":"1","unit":"large"},{"name":"Mustard seeds","quantity":"1","unit":"tsp"},{"name":"Curry leaves","quantity":"10","unit":"whole"},{"name":"Green chillies","quantity":"2","unit":"whole"},{"name":"Turmeric","quantity":"0.5","unit":"tsp"},{"name":"Oil","quantity":"3","unit":"tbsp"}]),"steps":j([{"order":1,"instruction":"Soak rice and urad dal separately for 6 hours. Grind to a smooth batter. Mix together and ferment overnight (8-12 hours)."},{"order":2,"instruction":"Make potato masala: heat oil, add mustard seeds, curry leaves, and green chillies. Add onions and cook until soft. Add turmeric and mashed potatoes. Mix well."},{"order":3,"instruction":"Heat a flat non-stick pan or cast iron tawa on medium-high. Sprinkle a few drops of water - it should sizzle."},{"order":4,"instruction":"Pour a ladle of batter in the centre. Quickly spread in a circular motion to make a thin crepe."},{"order":5,"instruction":"Drizzle oil around the edges. Cook until the bottom is golden and crispy."},{"order":6,"instruction":"Place potato masala on one half. Fold the dosa over. Serve immediately with coconut chutney and sambar."}]),"nutrition":j({"calories":280,"protein_g":8,"carbs_g":48,"fat_g":8,"serving_size":"1 dosa"}),"tips":j(["Fermentation is key - a warm environment speeds it up.","The batter should be slightly sour for authentic flavour.","A well-seasoned cast iron tawa gives the crispiest dosa.","Spread the batter quickly in one smooth circular motion."]),"youtube_query":"masala dosa recipe crispy","youtube_video_id":"Yw5UNqFBCow","prep_time":"20 minutes (plus overnight fermentation)","cook_time":"30 minutes","total_time":"14 hours","difficulty":"Hard","servings":"8 dosas","related_recipes":j(["idli-sambar","uttapam","dhokla"]),"published":1})

# 11 Samosa
recipes.append({"slug":"samosa","version":1,"title":"Samosa","category":"Indian","description":"Crispy, golden pastry triangles filled with a spiced potato and pea mixture. India's most beloved snack, perfect with mint chutney and a cup of chai.","hero_image_url":"https://images.unsplash.com/photo-1601050690597-df0568f70950?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixlib=rb-4.1.0&q=80&w=1080","meta_title":"Samosa Recipe - Crispy Spiced Potato Pastry","meta_description":"Crispy homemade samosas with spiced potato and pea filling. India's favourite snack, perfect with mint chutney.","keywords":j(["samosa","indian snack","potato samosa","fried pastry","indian street food"]),"ingredients":j([{"name":"All-purpose flour (maida)","quantity":"250","unit":"g"},{"name":"Oil (for dough)","quantity":"3","unit":"tbsp"},{"name":"Potatoes (boiled)","quantity":"400","unit":"g"},{"name":"Green peas","quantity":"100","unit":"g"},{"name":"Cumin seeds","quantity":"1","unit":"tsp"},{"name":"Coriander powder","quantity":"1","unit":"tsp"},{"name":"Garam masala","quantity":"0.5","unit":"tsp"},{"name":"Amchur","quantity":"0.5","unit":"tsp"},{"name":"Green chillies","quantity":"2","unit":"whole"},{"name":"Oil for deep frying","quantity":"500","unit":"ml"}]),"steps":j([{"order":1,"instruction":"Make dough: mix flour, oil, salt, and carom seeds (ajwain). Add water gradually to make a stiff dough. Rest 30 minutes."},{"order":2,"instruction":"Make filling: heat oil, add cumin seeds. Add green chillies, peas, and all spices. Add mashed potatoes and mix well. Cool completely."},{"order":3,"instruction":"Divide dough into balls. Roll each into an oval. Cut in half."},{"order":4,"instruction":"Form a cone from each half-oval. Fill with potato mixture. Seal the edges with water."},{"order":5,"instruction":"Deep fry in medium-hot oil (160C) for 8-10 minutes, turning occasionally, until golden and crispy."},{"order":6,"instruction":"Drain on paper towels. Serve hot with mint-coriander chutney and tamarind chutney."}]),"nutrition":j({"calories":220,"protein_g":5,"carbs_g":28,"fat_g":10,"serving_size":"2 samosas"}),"tips":j(["A stiff dough is essential for a crispy, non-oily samosa.","Fry on medium heat - high heat browns the outside before the pastry cooks through.","The filling must be completely cool before filling or the dough becomes soggy.","Carom seeds (ajwain) in the dough add flavour and aid digestion."]),"youtube_query":"samosa recipe crispy homemade","youtube_video_id":"Yw5UNqFBCow","prep_time":"30 minutes","cook_time":"30 minutes","total_time":"1 hour 30 minutes","difficulty":"Medium","servings":"12 samosas","related_recipes":j(["chole-bhature","paneer-tikka","aloo-paratha"]),"published":1})

# 12 Chicken Tikka Masala
recipes.append({"slug":"chicken-tikka-masala","version":1,"title":"Chicken Tikka Masala","category":"Indian","description":"Grilled chicken tikka pieces bathed in a rich, creamy, spiced tomato sauce. One of the most popular Indian dishes worldwide - smoky chicken meets a velvety, aromatic gravy.","hero_image_url":"https://images.unsplash.com/photo-1565557623262-b51c2513a641?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixlib=rb-4.1.0&q=80&w=1080","meta_title":"Chicken Tikka Masala Recipe - Smoky Chicken in Creamy Sauce","meta_description":"Smoky grilled chicken tikka in a rich, creamy tomato masala sauce. One of the world's most loved Indian dishes.","keywords":j(["chicken tikka masala","indian chicken curry","tikka masala","creamy chicken","popular indian"]),"ingredients":j([{"name":"Chicken breast (boneless)","quantity":"700","unit":"g"},{"name":"Plain yogurt","quantity":"150","unit":"g"},{"name":"Kashmiri chilli powder","quantity":"2","unit":"tsp"},{"name":"Garam masala","quantity":"2","unit":"tsp"},{"name":"Ginger-garlic paste","quantity":"2","unit":"tbsp"},{"name":"Onion","quantity":"2","unit":"large"},{"name":"Tomatoes","quantity":"400","unit":"g"},{"name":"Heavy cream","quantity":"150","unit":"ml"},{"name":"Butter","quantity":"30","unit":"g"},{"name":"Kasuri methi","quantity":"1","unit":"tbsp"},{"name":"Cardamom pods","quantity":"3","unit":"whole"}]),"steps":j([{"order":1,"instruction":"Marinate chicken in yogurt, 1 tsp chilli powder, 1 tsp garam masala, and ginger-garlic paste for 2 hours."},{"order":2,"instruction":"Grill or broil chicken until charred. Cut into bite-sized pieces."},{"order":3,"instruction":"Melt butter. Add cardamom pods. Saute onions until golden. Add ginger-garlic paste."},{"order":4,"instruction":"Add tomatoes and cook until completely soft. Blend to a smooth sauce and strain."},{"order":5,"instruction":"Return sauce to pan. Add remaining spices. Simmer 10 minutes."},{"order":6,"instruction":"Add grilled chicken, cream, and kasuri methi. Simmer 5 minutes. Serve with naan or rice."}]),"nutrition":j({"calories":390,"protein_g":36,"carbs_g":12,"fat_g":22,"serving_size":"1 serving"}),"tips":j(["Grilling the chicken separately before adding to the sauce is what makes this dish special.","Straining the sauce gives it a silky, restaurant-quality texture.","Kasuri methi added at the end is the secret flavour booster.","Use full-fat cream for the richest sauce."]),"youtube_query":"chicken tikka masala recipe","youtube_video_id":"Yw5UNqFBCow","prep_time":"20 minutes (plus 2 hours marinating)","cook_time":"40 minutes","total_time":"3 hours","difficulty":"Medium","servings":"4 servings","related_recipes":j(["butter-chicken","tandoori-chicken","dal-makhani"]),"published":1})

# 13 Gulab Jamun
recipes.append({"slug":"gulab-jamun","version":1,"title":"Gulab Jamun","category":"Indian","description":"Soft, melt-in-the-mouth milk solid dumplings deep-fried to a deep golden brown and soaked in a fragrant rose and cardamom sugar syrup. India's most beloved dessert.","hero_image_url":"https://images.unsplash.com/photo-1601050690597-df0568f70950?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixlib=rb-4.1.0&q=80&w=1080","meta_title":"Gulab Jamun Recipe - Soft Indian Milk Dumplings in Rose Syrup","meta_description":"Soft, melt-in-the-mouth gulab jamun soaked in rose and cardamom syrup. India's most beloved dessert.","keywords":j(["gulab jamun","indian dessert","milk dumplings","rose syrup","indian sweets"]),"ingredients":j([{"name":"Milk powder (full fat)","quantity":"200","unit":"g"},{"name":"All-purpose flour","quantity":"3","unit":"tbsp"},{"name":"Baking soda","quantity":"0.25","unit":"tsp"},{"name":"Ghee","quantity":"1","unit":"tbsp"},{"name":"Milk (warm)","quantity":"60","unit":"ml"},{"name":"Sugar","quantity":"300","unit":"g"},{"name":"Water","quantity":"300","unit":"ml"},{"name":"Rose water","quantity":"1","unit":"tbsp"},{"name":"Cardamom pods (crushed)","quantity":"4","unit":"whole"},{"name":"Oil for deep frying","quantity":"500","unit":"ml"}]),"steps":j([{"order":1,"instruction":"Make syrup: dissolve sugar in water. Add cardamom and rose water. Simmer 5 minutes until slightly sticky. Keep warm."},{"order":2,"instruction":"Mix milk powder, flour, and baking soda. Add ghee and mix. Add warm milk gradually to form a soft, smooth dough."},{"order":3,"instruction":"Divide into 20 equal portions. Roll into smooth balls with no cracks."},{"order":4,"instruction":"Heat oil to 150C (low-medium). Fry balls in batches, stirring gently, for 8-10 minutes until deep golden brown."},{"order":5,"instruction":"Drain briefly and immediately drop into warm sugar syrup."},{"order":6,"instruction":"Soak for at least 2 hours before serving. Serve warm or at room temperature."}]),"nutrition":j({"calories":180,"protein_g":4,"carbs_g":28,"fat_g":6,"serving_size":"2 pieces"}),"tips":j(["Fry on low heat - high heat browns the outside while the inside stays raw.","No cracks in the dough balls means they won't break while frying.","The syrup must be warm (not hot) when you add the fried jamuns.","Soaking for at least 2 hours is essential for the jamuns to absorb the syrup."]),"youtube_query":"gulab jamun recipe soft","youtube_video_id":"Yw5UNqFBCow","prep_time":"20 minutes","cook_time":"30 minutes","total_time":"3 hours (including soaking)","difficulty":"Medium","servings":"20 pieces","related_recipes":j(["kheer","jalebi","sooji-halwa"]),"published":1})

# 14 Mutton Biryani
recipes.append({"slug":"mutton-biryani","version":1,"title":"Mutton Biryani","category":"Indian","description":"Tender, slow-cooked mutton layered with fragrant saffron basmati rice and sealed for dum cooking. Richer and more complex than chicken biryani, this is a celebration dish.","hero_image_url":"https://images.unsplash.com/photo-1563379091339-03246963d96c?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixlib=rb-4.1.0&q=80&w=1080","meta_title":"Mutton Biryani Recipe - Authentic Dum Biryani","meta_description":"Rich, aromatic mutton biryani with tender slow-cooked lamb and saffron basmati rice. Authentic dum-cooked celebration dish.","keywords":j(["mutton biryani","lamb biryani","dum biryani","indian rice","celebration dish"]),"ingredients":j([{"name":"Mutton (bone-in)","quantity":"1","unit":"kg"},{"name":"Basmati rice","quantity":"400","unit":"g"},{"name":"Plain yogurt","quantity":"250","unit":"g"},{"name":"Onions","quantity":"4","unit":"large"},{"name":"Ginger-garlic paste","quantity":"3","unit":"tbsp"},{"name":"Biryani masala","quantity":"3","unit":"tbsp"},{"name":"Saffron","quantity":"1","unit":"pinch"},{"name":"Warm milk","quantity":"4","unit":"tbsp"},{"name":"Ghee","quantity":"5","unit":"tbsp"},{"name":"Whole spices","quantity":"1","unit":"set"},{"name":"Fresh mint and coriander","quantity":"1","unit":"handful each"}]),"steps":j([{"order":1,"instruction":"Marinate mutton in yogurt, ginger-garlic paste, biryani masala, and salt for at least 4 hours."},{"order":2,"instruction":"Fry onions until deep golden and crispy. Set aside half for garnish."},{"order":3,"instruction":"Cook marinated mutton with half the fried onions on medium heat for 30-40 minutes until 80% cooked."},{"order":4,"instruction":"Parboil rice with whole spices until 70% cooked. Drain."},{"order":5,"instruction":"Layer: mutton at bottom, then rice, then fried onions, mint, coriander, saffron milk, and ghee. Seal and dum cook 35 minutes on low heat."},{"order":6,"instruction":"Rest 15 minutes before opening. Gently mix and serve with raita and salad."}]),"nutrition":j({"calories":650,"protein_g":42,"carbs_g":60,"fat_g":24,"serving_size":"1 serving"}),"tips":j(["Mutton needs longer marinating and cooking than chicken.","Partially cooking the mutton before layering ensures it is fully cooked in the dum.","A heavy pot and low heat prevents the bottom from burning.","Resting after dum cooking allows the steam to redistribute."]),"youtube_query":"mutton biryani recipe authentic dum","youtube_video_id":"Yw5UNqFBCow","prep_time":"30 minutes (plus 4 hours marinating)","cook_time":"1 hour 30 minutes","total_time":"6 hours","difficulty":"Hard","servings":"5 servings","related_recipes":j(["chicken-biryani","butter-chicken","dal-makhani"]),"published":1})

# 15 Pani Puri
recipes.append({"slug":"pani-puri","version":1,"title":"Pani Puri (Golgappa)","category":"Indian","description":"Hollow crispy puri shells filled with spiced potato and chickpea, then dunked in a tangy, spicy, minty water. India's most addictive street food - an explosion of flavours in one bite.","hero_image_url":"https://images.unsplash.com/photo-1601050690597-df0568f70950?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixlib=rb-4.1.0&q=80&w=1080","meta_title":"Pani Puri Recipe (Golgappa) - Indian Street Food","meta_description":"Crispy puri shells with spiced potato filling and tangy mint water. India's most beloved street food snack.","keywords":j(["pani puri","golgappa","indian street food","chaat","spicy snack"]),"ingredients":j([{"name":"Semolina (sooji)","quantity":"150","unit":"g"},{"name":"All-purpose flour","quantity":"2","unit":"tbsp"},{"name":"Potatoes (boiled)","quantity":"200","unit":"g"},{"name":"Boiled chickpeas","quantity":"100","unit":"g"},{"name":"Fresh mint leaves","quantity":"50","unit":"g"},{"name":"Fresh coriander","quantity":"30","unit":"g"},{"name":"Green chillies","quantity":"3","unit":"whole"},{"name":"Tamarind paste","quantity":"2","unit":"tbsp"},{"name":"Chaat masala","quantity":"1","unit":"tsp"},{"name":"Black salt (kala namak)","quantity":"1","unit":"tsp"},{"name":"Oil for deep frying","quantity":"500","unit":"ml"}]),"steps":j([{"order":1,"instruction":"Make puri dough: mix semolina, flour, and salt. Add water to make a stiff dough. Rest 20 minutes. Roll thin and cut into small circles."},{"order":2,"instruction":"Deep fry puri circles in hot oil, pressing them down so they puff up. Fry until golden and crispy."},{"order":3,"instruction":"Make pani: blend mint, coriander, green chillies, tamarind, chaat masala, black salt, and cumin with cold water. Strain and chill."},{"order":4,"instruction":"Make filling: mash potatoes with chickpeas, chaat masala, and salt."},{"order":5,"instruction":"To serve: make a small hole in each puri. Fill with potato mixture."},{"order":6,"instruction":"Dunk filled puri in the chilled pani and eat immediately in one bite."}]),"nutrition":j({"calories":180,"protein_g":4,"carbs_g":28,"fat_g":6,"serving_size":"6 pieces"}),"tips":j(["The dough must be stiff for crispy puris that don't absorb oil.","Press the puris down in oil immediately so they puff up evenly.","Black salt (kala namak) is essential for authentic pani flavour.","Serve immediately after filling - they go soggy quickly."]),"youtube_query":"pani puri recipe homemade golgappa","youtube_video_id":"Yw5UNqFBCow","prep_time":"30 minutes","cook_time":"30 minutes","total_time":"1 hour","difficulty":"Medium","servings":"30 pieces","related_recipes":j(["samosa","chole-bhature","pav-bhaji"]),"published":1})

# 16 Kheer
recipes.append({"slug":"kheer","version":1,"title":"Kheer (Rice Pudding)","category":"Indian","description":"Creamy, slow-cooked rice pudding infused with cardamom, saffron, and rose water, garnished with pistachios and almonds. India's most cherished festive dessert.","hero_image_url":"https://images.unsplash.com/photo-1601050690597-df0568f70950?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixlib=rb-4.1.0&q=80&w=1080","meta_title":"Kheer Recipe - Indian Creamy Rice Pudding","meta_description":"Creamy Indian kheer with rice, milk, cardamom, and saffron. A classic festive dessert ready in 45 minutes.","keywords":j(["kheer","indian rice pudding","indian dessert","festive sweet","cardamom rice"]),"ingredients":j([{"name":"Basmati rice","quantity":"60","unit":"g"},{"name":"Full-fat milk","quantity":"1","unit":"litre"},{"name":"Sugar","quantity":"80","unit":"g"},{"name":"Cardamom pods (crushed)","quantity":"4","unit":"whole"},{"name":"Saffron","quantity":"1","unit":"pinch"},{"name":"Rose water","quantity":"1","unit":"tsp"},{"name":"Pistachios (sliced)","quantity":"30","unit":"g"},{"name":"Almonds (sliced)","quantity":"30","unit":"g"}]),"steps":j([{"order":1,"instruction":"Wash and soak rice for 20 minutes. Drain."},{"order":2,"instruction":"Bring milk to a boil in a heavy-bottomed pan. Add soaked rice."},{"order":3,"instruction":"Simmer on medium-low heat, stirring frequently, for 30-35 minutes until rice is completely soft and milk has thickened."},{"order":4,"instruction":"Add sugar, crushed cardamom, and saffron. Stir and cook 5 more minutes."},{"order":5,"instruction":"Remove from heat. Add rose water."},{"order":6,"instruction":"Serve warm or chilled, garnished with pistachios and almonds."}]),"nutrition":j({"calories":220,"protein_g":7,"carbs_g":34,"fat_g":7,"serving_size":"1 serving"}),"tips":j(["Stir frequently to prevent the milk from scorching at the bottom.","The kheer thickens further as it cools - remove from heat when slightly thinner than desired.","Saffron soaked in a tablespoon of warm milk gives a more vibrant colour.","Chilled kheer is equally delicious and keeps well for 2 days."]),"youtube_query":"kheer recipe indian rice pudding","youtube_video_id":"Yw5UNqFBCow","prep_time":"5 minutes","cook_time":"45 minutes","total_time":"50 minutes","difficulty":"Easy","servings":"4 servings","related_recipes":j(["gulab-jamun","jalebi","sooji-halwa"]),"published":1})

# 17 Idli Sambar
recipes.append({"slug":"idli-sambar","version":1,"title":"Idli with Sambar","category":"Indian","description":"Soft, fluffy steamed rice and lentil cakes served with a tangy, spiced lentil and vegetable soup (sambar) and coconut chutney. The quintessential South Indian breakfast.","hero_image_url":"https://images.unsplash.com/photo-1589301760014-d929f3979dbc?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixlib=rb-4.1.0&q=80&w=1080","meta_title":"Idli Sambar Recipe - Soft South Indian Steamed Cakes","meta_description":"Soft, fluffy idli with tangy sambar and coconut chutney. Classic South Indian breakfast recipe.","keywords":j(["idli sambar","south indian breakfast","steamed idli","sambar recipe","healthy indian"]),"ingredients":j([{"name":"Parboiled rice","quantity":"300","unit":"g"},{"name":"Urad dal","quantity":"100","unit":"g"},{"name":"Fenugreek seeds","quantity":"0.5","unit":"tsp"},{"name":"Toor dal (split pigeon peas)","quantity":"150","unit":"g"},{"name":"Mixed vegetables (drumstick, carrot, onion)","quantity":"200","unit":"g"},{"name":"Tamarind paste","quantity":"2","unit":"tbsp"},{"name":"Sambar powder","quantity":"2","unit":"tbsp"},{"name":"Mustard seeds","quantity":"1","unit":"tsp"},{"name":"Curry leaves","quantity":"10","unit":"whole"},{"name":"Dried red chillies","quantity":"2","unit":"whole"}]),"steps":j([{"order":1,"instruction":"Soak rice and urad dal separately for 6 hours. Grind to a smooth batter. Ferment overnight."},{"order":2,"instruction":"Add salt to batter. Pour into greased idli moulds. Steam for 10-12 minutes until a toothpick comes out clean."},{"order":3,"instruction":"Cook toor dal until soft. Mash lightly."},{"order":4,"instruction":"Add tamarind water, sambar powder, vegetables, and salt to the dal. Simmer 15 minutes."},{"order":5,"instruction":"Make tempering: heat oil, add mustard seeds, curry leaves, and dried chillies. Pour over sambar."},{"order":6,"instruction":"Serve hot idlis with sambar and coconut chutney."}]),"nutrition":j({"calories":240,"protein_g":10,"carbs_g":44,"fat_g":3,"serving_size":"3 idlis with sambar"}),"tips":j(["Fermentation is key - a warm environment (28-30C) speeds it up.","Do not overfill idli moulds - the batter expands while steaming.","Sambar tastes better the next day as the flavours meld.","Wet-grind the batter for the softest, fluffiest idlis."]),"youtube_query":"idli sambar recipe soft fluffy","youtube_video_id":"Yw5UNqFBCow","prep_time":"20 minutes (plus overnight fermentation)","cook_time":"30 minutes","total_time":"14 hours","difficulty":"Medium","servings":"4 servings","related_recipes":j(["masala-dosa","uttapam","dhokla"]),"published":1})

# 18 Veg Biryani
recipes.append({"slug":"veg-biryani","version":1,"title":"Vegetable Biryani","category":"Indian","description":"Fragrant basmati rice cooked with colourful vegetables, whole spices, and saffron using the dum method. A stunning vegetarian biryani that is every bit as flavourful as its meat counterpart.","hero_image_url":"https://images.unsplash.com/photo-1563379091339-03246963d96c?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixlib=rb-4.1.0&q=80&w=1080","meta_title":"Vegetable Biryani Recipe - Fragrant Dum Biryani","meta_description":"Fragrant vegetable biryani with saffron basmati rice and mixed vegetables. Authentic dum-cooked vegetarian biryani.","keywords":j(["veg biryani","vegetable biryani","vegetarian biryani","indian rice","dum biryani"]),"ingredients":j([{"name":"Basmati rice","quantity":"400","unit":"g"},{"name":"Mixed vegetables (carrot, beans, peas, potato)","quantity":"400","unit":"g"},{"name":"Onions","quantity":"3","unit":"large"},{"name":"Plain yogurt","quantity":"150","unit":"g"},{"name":"Ginger-garlic paste","quantity":"2","unit":"tbsp"},{"name":"Biryani masala","quantity":"2","unit":"tbsp"},{"name":"Saffron","quantity":"1","unit":"pinch"},{"name":"Warm milk","quantity":"4","unit":"tbsp"},{"name":"Ghee","quantity":"4","unit":"tbsp"},{"name":"Whole spices","quantity":"1","unit":"set"},{"name":"Fresh mint and coriander","quantity":"1","unit":"handful each"}]),"steps":j([{"order":1,"instruction":"Marinate vegetables in yogurt, ginger-garlic paste, biryani masala, and salt for 1 hour."},{"order":2,"instruction":"Fry onions until deep golden and crispy. Set aside half for garnish."},{"order":3,"instruction":"Cook marinated vegetables with half the fried onions for 10 minutes."},{"order":4,"instruction":"Parboil rice with whole spices until 70% cooked. Drain."},{"order":5,"instruction":"Layer vegetables at bottom, then rice, fried onions, mint, coriander, saffron milk, and ghee. Seal and dum cook 25 minutes."},{"order":6,"instruction":"Rest 10 minutes. Gently mix and serve with raita."}]),"nutrition":j({"calories":420,"protein_g":10,"carbs_g":72,"fat_g":12,"serving_size":"1 serving"}),"tips":j(["Cut vegetables into large chunks so they don't turn mushy.","Marinating vegetables adds depth of flavour.","The dum process is what makes biryani special - don't rush it.","A layer of caramelised onions between rice layers adds sweetness."]),"youtube_query":"vegetable biryani recipe dum style","youtube_video_id":"Yw5UNqFBCow","prep_time":"20 minutes (plus 1 hour marinating)","cook_time":"50 minutes","total_time":"2 hours","difficulty":"Medium","servings":"4 servings","related_recipes":j(["chicken-biryani","palak-paneer","dal-makhani"]),"published":1})

# 19 Aloo Gobi
recipes.append({"slug":"aloo-gobi","version":1,"title":"Aloo Gobi","category":"Indian","description":"A dry, fragrant stir-fry of potatoes and cauliflower with turmeric, cumin, and garam masala. Simple, wholesome, and deeply satisfying - a staple of every Indian home kitchen.","hero_image_url":"https://images.unsplash.com/photo-1565557623262-b51c2513a641?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixlib=rb-4.1.0&q=80&w=1080","meta_title":"Aloo Gobi Recipe - Spiced Potato and Cauliflower","meta_description":"Classic aloo gobi with spiced potatoes and cauliflower. Simple, wholesome Indian vegetarian dish ready in 30 minutes.","keywords":j(["aloo gobi","potato cauliflower","indian vegetarian","dry curry","home cooking"]),"ingredients":j([{"name":"Potatoes","quantity":"300","unit":"g"},{"name":"Cauliflower","quantity":"400","unit":"g"},{"name":"Onion","quantity":"1","unit":"medium"},{"name":"Tomato","quantity":"1","unit":"medium"},{"name":"Ginger-garlic paste","quantity":"1","unit":"tbsp"},{"name":"Turmeric","quantity":"0.5","unit":"tsp"},{"name":"Cumin seeds","quantity":"1","unit":"tsp"},{"name":"Coriander powder","quantity":"1","unit":"tsp"},{"name":"Garam masala","quantity":"0.5","unit":"tsp"},{"name":"Oil","quantity":"3","unit":"tbsp"},{"name":"Fresh coriander","quantity":"2","unit":"tbsp"}]),"steps":j([{"order":1,"instruction":"Cut potatoes and cauliflower into similar-sized florets. Parboil potatoes for 5 minutes."},{"order":2,"instruction":"Heat oil. Add cumin seeds. Once they splutter, add onions and cook until golden."},{"order":3,"instruction":"Add ginger-garlic paste and tomato. Cook until soft."},{"order":4,"instruction":"Add turmeric, coriander powder, and salt. Add cauliflower and potatoes."},{"order":5,"instruction":"Stir well to coat with spices. Cover and cook on low heat for 15 minutes, stirring occasionally."},{"order":6,"instruction":"Add garam masala and fresh coriander. Serve with roti or paratha."}]),"nutrition":j({"calories":220,"protein_g":5,"carbs_g":32,"fat_g":9,"serving_size":"1 serving"}),"tips":j(["Do not add water - the vegetables release enough moisture.","Parboiling potatoes ensures they cook through without the spinach becoming mushy.","Cook on low heat to avoid burning and to develop flavour.","A pinch of amchur at the end adds a lovely tanginess."]),"youtube_query":"aloo gobi recipe dhaba style","youtube_video_id":"Yw5UNqFBCow","prep_time":"10 minutes","cook_time":"25 minutes","total_time":"35 minutes","difficulty":"Easy","servings":"4 servings","related_recipes":j(["aloo-paratha","palak-paneer","rajma-chawal"]),"published":1})

# 20 Naan
recipes.append({"slug":"naan-bread","version":1,"title":"Naan Bread","category":"Indian","description":"Soft, pillowy leavened flatbread with charred bubbles, brushed with garlic butter. The perfect companion to any Indian curry - made at home without a tandoor.","hero_image_url":"https://images.unsplash.com/photo-1565557623262-b51c2513a641?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixlib=rb-4.1.0&q=80&w=1080","meta_title":"Naan Bread Recipe - Soft Garlic Butter Flatbread","meta_description":"Soft, pillowy naan bread with garlic butter. Made at home without a tandoor - perfect with any Indian curry.","keywords":j(["naan bread","garlic naan","indian flatbread","homemade naan","indian bread"]),"ingredients":j([{"name":"All-purpose flour","quantity":"300","unit":"g"},{"name":"Instant yeast","quantity":"1","unit":"tsp"},{"name":"Sugar","quantity":"1","unit":"tsp"},{"name":"Salt","quantity":"1","unit":"tsp"},{"name":"Plain yogurt","quantity":"100","unit":"g"},{"name":"Warm milk","quantity":"100","unit":"ml"},{"name":"Oil","quantity":"2","unit":"tbsp"},{"name":"Butter","quantity":"50","unit":"g"},{"name":"Garlic (minced)","quantity":"3","unit":"cloves"},{"name":"Fresh coriander","quantity":"2","unit":"tbsp"}]),"steps":j([{"order":1,"instruction":"Mix flour, yeast, sugar, and salt. Add yogurt, warm milk, and oil. Knead to a soft, smooth dough. Cover and rest 1 hour until doubled."},{"order":2,"instruction":"Divide dough into 6 balls. Roll each into a teardrop shape, about 5mm thick."},{"order":3,"instruction":"Heat a cast iron pan or tawa on high heat until very hot."},{"order":4,"instruction":"Place naan on the dry pan. Cook 2 minutes until bubbles form and the bottom has dark spots."},{"order":5,"instruction":"Flip and cook 1 minute more. Alternatively, hold over a gas flame for charred spots."},{"order":6,"instruction":"Brush immediately with garlic butter and sprinkle with fresh coriander. Serve hot."}]),"nutrition":j({"calories":280,"protein_g":7,"carbs_g":42,"fat_g":9,"serving_size":"1 naan"}),"tips":j(["A very hot pan is essential for the characteristic charred bubbles.","Yogurt in the dough makes naan soft and slightly tangy.","Brush with butter immediately off the pan so it melts in.","Naan is best eaten fresh - it stiffens as it cools."]),"youtube_query":"naan bread recipe without tandoor","youtube_video_id":"Yw5UNqFBCow","prep_time":"15 minutes (plus 1 hour rising)","cook_time":"20 minutes","total_time":"1 hour 35 minutes","difficulty":"Easy","servings":"6 naans","related_recipes":j(["butter-chicken","dal-makhani","palak-paneer"]),"published":1})

# 21 Chana Masala
recipes.append({"slug":"chana-masala","version":1,"title":"Chana Masala","category":"Indian","description":"Hearty chickpeas cooked in a bold, tangy, spiced tomato-onion gravy. A protein-packed vegetarian curry that is a staple across North India, served with rice or bhature.","hero_image_url":"https://images.unsplash.com/photo-1626132647523-66c3f4942d4b?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixlib=rb-4.1.0&q=80&w=1080","meta_title":"Chana Masala Recipe - Spiced Chickpea Curry","meta_description":"Bold, tangy chana masala with hearty chickpeas in a spiced tomato gravy. Protein-packed vegetarian Indian curry.","keywords":j(["chana masala","chickpea curry","indian vegetarian","chole","protein curry"]),"ingredients":j([{"name":"Chickpeas (dried)","quantity":"250","unit":"g"},{"name":"Onions","quantity":"2","unit":"large"},{"name":"Tomatoes","quantity":"3","unit":"medium"},{"name":"Ginger-garlic paste","quantity":"2","unit":"tbsp"},{"name":"Chana masala powder","quantity":"2","unit":"tbsp"},{"name":"Cumin seeds","quantity":"1","unit":"tsp"},{"name":"Amchur","quantity":"1","unit":"tsp"},{"name":"Pomegranate powder (anardana)","quantity":"1","unit":"tsp"},{"name":"Oil","quantity":"3","unit":"tbsp"},{"name":"Fresh coriander","quantity":"2","unit":"tbsp"}]),"steps":j([{"order":1,"instruction":"Soak chickpeas overnight. Pressure cook until completely soft, about 20 minutes."},{"order":2,"instruction":"Heat oil. Add cumin seeds. Add onions and cook until deep golden."},{"order":3,"instruction":"Add ginger-garlic paste and tomatoes. Cook until oil separates."},{"order":4,"instruction":"Add chana masala, amchur, anardana, and salt. Cook 2 minutes."},{"order":5,"instruction":"Add cooked chickpeas with some cooking liquid. Simmer 20 minutes, mashing some chickpeas."},{"order":6,"instruction":"Garnish with fresh coriander and a squeeze of lemon. Serve with rice or bhature."}]),"nutrition":j({"calories":320,"protein_g":14,"carbs_g":48,"fat_g":9,"serving_size":"1 serving"}),"tips":j(["Anardana (pomegranate powder) gives chana masala its distinctive tangy depth.","Mashing some chickpeas thickens the gravy naturally.","The curry should be thick and coating the chickpeas, not watery.","A squeeze of lemon at the end brightens all the flavours."]),"youtube_query":"chana masala recipe restaurant style","youtube_video_id":"Yw5UNqFBCow","prep_time":"10 minutes (plus overnight soaking)","cook_time":"40 minutes","total_time":"1 hour","difficulty":"Easy","servings":"4 servings","related_recipes":j(["chole-bhature","rajma-chawal","dal-makhani"]),"published":1})

# 22 Matar Paneer
recipes.append({"slug":"matar-paneer","version":1,"title":"Matar Paneer","category":"Indian","description":"Soft paneer cubes and sweet green peas in a rich, spiced tomato-onion gravy. A classic North Indian vegetarian curry that is quick to make and universally loved.","hero_image_url":"https://images.unsplash.com/photo-1601050690597-df0568f70950?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixlib=rb-4.1.0&q=80&w=1080","meta_title":"Matar Paneer Recipe - Peas and Cottage Cheese Curry","meta_description":"Classic matar paneer with soft paneer and green peas in a rich spiced tomato gravy. Quick North Indian vegetarian curry.","keywords":j(["matar paneer","peas paneer","indian vegetarian","paneer curry","north indian"]),"ingredients":j([{"name":"Paneer","quantity":"300","unit":"g"},{"name":"Green peas (fresh or frozen)","quantity":"200","unit":"g"},{"name":"Onion","quantity":"2","unit":"medium"},{"name":"Tomatoes","quantity":"3","unit":"medium"},{"name":"Ginger-garlic paste","quantity":"1","unit":"tbsp"},{"name":"Cumin seeds","quantity":"1","unit":"tsp"},{"name":"Coriander powder","quantity":"1","unit":"tsp"},{"name":"Garam masala","quantity":"1","unit":"tsp"},{"name":"Kashmiri chilli powder","quantity":"1","unit":"tsp"},{"name":"Cream","quantity":"2","unit":"tbsp"},{"name":"Oil","quantity":"3","unit":"tbsp"}]),"steps":j([{"order":1,"instruction":"Fry paneer cubes in oil until golden. Set aside."},{"order":2,"instruction":"In the same pan, add cumin seeds. Add onions and cook until golden."},{"order":3,"instruction":"Add ginger-garlic paste and tomatoes. Cook until oil separates."},{"order":4,"instruction":"Add all spices and salt. Cook 2 minutes."},{"order":5,"instruction":"Add green peas and a splash of water. Cook 5 minutes."},{"order":6,"instruction":"Add fried paneer and cream. Simmer 5 minutes. Serve with roti or rice."}]),"nutrition":j({"calories":300,"protein_g":16,"carbs_g":18,"fat_g":20,"serving_size":"1 serving"}),"tips":j(["Frying paneer gives it a golden crust that holds up in the gravy.","Fresh peas are sweeter but frozen work perfectly well.","Do not overcook the peas - they should retain a slight bite.","A pinch of sugar balances the acidity of the tomatoes."]),"youtube_query":"matar paneer recipe restaurant style","youtube_video_id":"Yw5UNqFBCow","prep_time":"10 minutes","cook_time":"25 minutes","total_time":"35 minutes","difficulty":"Easy","servings":"4 servings","related_recipes":j(["palak-paneer","paneer-tikka","butter-chicken"]),"published":1})

# 23 Sooji Halwa
recipes.append({"slug":"sooji-halwa","version":1,"title":"Sooji Halwa (Semolina Pudding)","category":"Indian","description":"A warm, fragrant semolina pudding cooked in ghee with sugar, cardamom, and garnished with cashews and raisins. A quick, comforting Indian dessert made in under 20 minutes.","hero_image_url":"https://images.unsplash.com/photo-1601050690597-df0568f70950?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixlib=rb-4.1.0&q=80&w=1080","meta_title":"Sooji Halwa Recipe - Indian Semolina Pudding","meta_description":"Warm, fragrant sooji halwa with semolina, ghee, and cardamom. Quick Indian dessert ready in 20 minutes.","keywords":j(["sooji halwa","semolina pudding","indian dessert","quick sweet","halwa recipe"]),"ingredients":j([{"name":"Semolina (sooji/rava)","quantity":"150","unit":"g"},{"name":"Ghee","quantity":"60","unit":"g"},{"name":"Sugar","quantity":"120","unit":"g"},{"name":"Water","quantity":"400","unit":"ml"},{"name":"Cardamom powder","quantity":"0.5","unit":"tsp"},{"name":"Cashews","quantity":"20","unit":"g"},{"name":"Raisins","quantity":"20","unit":"g"},{"name":"Saffron (optional)","quantity":"1","unit":"pinch"}]),"steps":j([{"order":1,"instruction":"Heat ghee in a pan. Fry cashews and raisins until golden. Remove and set aside."},{"order":2,"instruction":"In the same ghee, add semolina. Roast on medium heat, stirring constantly, for 8-10 minutes until golden and fragrant."},{"order":3,"instruction":"Meanwhile, bring water and sugar to a boil. Add saffron if using."},{"order":4,"instruction":"Carefully pour the hot sugar water into the roasted semolina (it will splutter). Stir vigorously."},{"order":5,"instruction":"Cook on low heat, stirring, until the halwa comes together and leaves the sides of the pan."},{"order":6,"instruction":"Add cardamom powder. Garnish with fried cashews and raisins. Serve warm."}]),"nutrition":j({"calories":280,"protein_g":4,"carbs_g":42,"fat_g":11,"serving_size":"1 serving"}),"tips":j(["Roasting the semolina in ghee until golden is the most important step for flavour.","Have the hot sugar water ready before adding to the semolina.","The halwa is done when it pulls away from the sides of the pan.","A pinch of saffron adds a beautiful golden colour and aroma."]),"youtube_query":"sooji halwa recipe quick","youtube_video_id":"Yw5UNqFBCow","prep_time":"5 minutes","cook_time":"20 minutes","total_time":"25 minutes","difficulty":"Easy","servings":"4 servings","related_recipes":j(["kheer","gulab-jamun","jalebi"]),"published":1})

# 24 Goan Fish Curry
recipes.append({"slug":"goan-fish-curry","version":1,"title":"Goan Fish Curry","category":"Indian","description":"A vibrant, tangy coconut-based fish curry from the coastal state of Goa. Flavoured with kokum (or tamarind), fresh coconut, and a blend of Goan spices. Light, fragrant, and deeply satisfying.","hero_image_url":"https://images.unsplash.com/photo-1565557623262-b51c2513a641?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixlib=rb-4.1.0&q=80&w=1080","meta_title":"Goan Fish Curry Recipe - Coconut Tamarind Fish Curry","meta_description":"Vibrant Goan fish curry with coconut milk, kokum, and aromatic spices. Authentic coastal Indian recipe.","keywords":j(["goan fish curry","coconut fish curry","goa recipe","indian fish","coastal curry"]),"ingredients":j([{"name":"Fish fillets (pomfret or kingfish)","quantity":"600","unit":"g"},{"name":"Coconut milk","quantity":"400","unit":"ml"},{"name":"Onion","quantity":"1","unit":"large"},{"name":"Tomato","quantity":"2","unit":"medium"},{"name":"Ginger-garlic paste","quantity":"1","unit":"tbsp"},{"name":"Kokum or tamarind paste","quantity":"2","unit":"tbsp"},{"name":"Kashmiri chilli powder","quantity":"2","unit":"tsp"},{"name":"Coriander powder","quantity":"1","unit":"tsp"},{"name":"Turmeric","quantity":"0.5","unit":"tsp"},{"name":"Mustard seeds","quantity":"1","unit":"tsp"},{"name":"Curry leaves","quantity":"10","unit":"whole"},{"name":"Oil","quantity":"3","unit":"tbsp"}]),"steps":j([{"order":1,"instruction":"Marinate fish with turmeric and salt for 15 minutes."},{"order":2,"instruction":"Heat oil. Add mustard seeds and curry leaves. Add onions and cook until golden."},{"order":3,"instruction":"Add ginger-garlic paste and tomatoes. Cook until soft."},{"order":4,"instruction":"Add chilli powder, coriander powder, and turmeric. Cook 2 minutes."},{"order":5,"instruction":"Add coconut milk and kokum. Bring to a gentle simmer."},{"order":6,"instruction":"Add marinated fish. Simmer gently for 8-10 minutes until fish is cooked through. Serve with steamed rice."}]),"nutrition":j({"calories":340,"protein_g":32,"carbs_g":10,"fat_g":20,"serving_size":"1 serving"}),"tips":j(["Do not overcook the fish - it becomes rubbery.","Kokum gives a more authentic Goan flavour than tamarind.","Simmer gently after adding fish - vigorous boiling breaks the fish apart.","Goan curry tastes even better the next day."]),"youtube_query":"goan fish curry recipe authentic","youtube_video_id":"Yw5UNqFBCow","prep_time":"15 minutes","cook_time":"25 minutes","total_time":"40 minutes","difficulty":"Easy","servings":"4 servings","related_recipes":j(["butter-chicken","chicken-biryani","dal-makhani"]),"published":1})

# 25 Jalebi
recipes.append({"slug":"jalebi","version":1,"title":"Jalebi","category":"Indian","description":"Crispy, syrup-soaked spiral fritters made from fermented batter. Bright orange, crunchy on the outside, and bursting with sweet sugar syrup inside. India's most iconic street dessert.","hero_image_url":"https://images.unsplash.com/photo-1601050690597-df0568f70950?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixlib=rb-4.1.0&q=80&w=1080","meta_title":"Jalebi Recipe - Crispy Indian Syrup Spirals","meta_description":"Crispy, syrup-soaked jalebi spirals. Classic Indian street dessert with fermented batter and saffron sugar syrup.","keywords":j(["jalebi","indian sweet","crispy jalebi","street dessert","indian festival sweet"]),"ingredients":j([{"name":"All-purpose flour","quantity":"200","unit":"g"},{"name":"Cornstarch","quantity":"2","unit":"tbsp"},{"name":"Plain yogurt","quantity":"2","unit":"tbsp"},{"name":"Baking soda","quantity":"0.25","unit":"tsp"},{"name":"Orange food colour","quantity":"1","unit":"pinch"},{"name":"Sugar","quantity":"300","unit":"g"},{"name":"Water","quantity":"200","unit":"ml"},{"name":"Saffron","quantity":"1","unit":"pinch"},{"name":"Cardamom powder","quantity":"0.25","unit":"tsp"},{"name":"Oil for deep frying","quantity":"500","unit":"ml"}]),"steps":j([{"order":1,"instruction":"Make batter: mix flour, cornstarch, yogurt, baking soda, food colour, and enough water to make a smooth, flowing batter. Ferment 8-12 hours."},{"order":2,"instruction":"Make syrup: dissolve sugar in water. Add saffron and cardamom. Simmer to one-string consistency. Keep warm."},{"order":3,"instruction":"Heat oil to 180C. Pour batter into a squeeze bottle or piping bag."},{"order":4,"instruction":"Pipe batter in spiral shapes directly into the hot oil. Fry 2-3 minutes until crispy."},{"order":5,"instruction":"Remove from oil and immediately dip in warm sugar syrup for 30 seconds."},{"order":6,"instruction":"Remove from syrup and serve immediately while still crispy."}]),"nutrition":j({"calories":240,"protein_g":3,"carbs_g":48,"fat_g":5,"serving_size":"4 pieces"}),"tips":j(["The batter should be smooth and flow easily - not too thick or thin.","One-string syrup consistency is key - too thin and jalebi won't be sweet enough.","Dip in syrup immediately after frying while still hot.","Serve immediately - jalebi loses its crispness within minutes."]),"youtube_query":"jalebi recipe crispy homemade","youtube_video_id":"Yw5UNqFBCow","prep_time":"10 minutes (plus overnight fermentation)","cook_time":"30 minutes","total_time":"12 hours","difficulty":"Hard","servings":"20 pieces","related_recipes":j(["gulab-jamun","kheer","sooji-halwa"]),"published":1})

# 26 Rogan Josh
recipes.append({"slug":"rogan-josh","version":1,"title":"Rogan Josh","category":"Indian","description":"A signature Kashmiri lamb curry with a deep red, aromatic gravy made with Kashmiri chillies, whole spices, and yogurt. Slow-cooked until the lamb is fall-off-the-bone tender.","hero_image_url":"https://images.unsplash.com/photo-1565557623262-b51c2513a641?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixlib=rb-4.1.0&q=80&w=1080","meta_title":"Rogan Josh Recipe - Kashmiri Lamb Curry","meta_description":"Authentic Kashmiri rogan josh with tender lamb in a deep red aromatic gravy. Slow-cooked for maximum flavour.","keywords":j(["rogan josh","kashmiri curry","lamb curry","indian lamb","slow cooked"]),"ingredients":j([{"name":"Lamb (bone-in)","quantity":"1","unit":"kg"},{"name":"Plain yogurt","quantity":"200","unit":"g"},{"name":"Kashmiri chilli powder","quantity":"3","unit":"tsp"},{"name":"Fennel powder","quantity":"2","unit":"tsp"},{"name":"Ginger powder","quantity":"1","unit":"tsp"},{"name":"Whole spices (cardamom, cloves, cinnamon, bay leaf)","quantity":"1","unit":"set"},{"name":"Onion","quantity":"2","unit":"large"},{"name":"Ghee","quantity":"4","unit":"tbsp"},{"name":"Asafoetida (hing)","quantity":"1","unit":"pinch"},{"name":"Garam masala","quantity":"1","unit":"tsp"}]),"steps":j([{"order":1,"instruction":"Heat ghee. Add whole spices and asafoetida. Add onions and cook until deep golden."},{"order":2,"instruction":"Add lamb pieces and brown on all sides on high heat."},{"order":3,"instruction":"Add Kashmiri chilli powder, fennel powder, and ginger powder. Stir well."},{"order":4,"instruction":"Add beaten yogurt gradually, stirring constantly to prevent curdling."},{"order":5,"instruction":"Add water to cover. Bring to a boil, then simmer covered for 1 hour until lamb is tender."},{"order":6,"instruction":"Add garam masala. Simmer uncovered 10 minutes to reduce the gravy. Serve with rice or naan."}]),"nutrition":j({"calories":480,"protein_g":42,"carbs_g":8,"fat_g":30,"serving_size":"1 serving"}),"tips":j(["Kashmiri chillies give the iconic deep red colour without excessive heat.","Add yogurt gradually and stir constantly to prevent it from splitting.","Bone-in lamb gives far more flavour than boneless.","Fennel powder is the signature spice of Kashmiri cuisine - do not substitute."]),"youtube_query":"rogan josh recipe kashmiri lamb","youtube_video_id":"Yw5UNqFBCow","prep_time":"15 minutes","cook_time":"1 hour 20 minutes","total_time":"1 hour 35 minutes","difficulty":"Medium","servings":"4 servings","related_recipes":j(["butter-chicken","mutton-biryani","dal-makhani"]),"published":1})

# 27 Pav Bhaji
recipes.append({"slug":"pav-bhaji","version":1,"title":"Pav Bhaji","category":"Indian","description":"A thick, spiced vegetable mash cooked on a flat griddle with butter, served with soft buttered bread rolls. Mumbai's most iconic street food - bold, buttery, and utterly addictive.","hero_image_url":"https://images.unsplash.com/photo-1565557623262-b51c2513a641?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixlib=rb-4.1.0&q=80&w=1080","meta_title":"Pav Bhaji Recipe - Mumbai Street Food","meta_description":"Classic Mumbai pav bhaji with spiced vegetable mash and buttered bread rolls. Iconic Indian street food.","keywords":j(["pav bhaji","mumbai street food","indian street food","vegetable mash","bhaji recipe"]),"ingredients":j([{"name":"Potatoes (boiled)","quantity":"400","unit":"g"},{"name":"Cauliflower","quantity":"200","unit":"g"},{"name":"Green peas","quantity":"100","unit":"g"},{"name":"Capsicum","quantity":"1","unit":"medium"},{"name":"Onions","quantity":"2","unit":"large"},{"name":"Tomatoes","quantity":"3","unit":"large"},{"name":"Pav bhaji masala","quantity":"3","unit":"tbsp"},{"name":"Butter","quantity":"80","unit":"g"},{"name":"Ginger-garlic paste","quantity":"1","unit":"tbsp"},{"name":"Pav (bread rolls)","quantity":"8","unit":"whole"},{"name":"Lemon juice","quantity":"2","unit":"tbsp"}]),"steps":j([{"order":1,"instruction":"Boil cauliflower and peas until soft. Mash all vegetables together."},{"order":2,"instruction":"Heat butter on a flat griddle or pan. Saute onions until golden."},{"order":3,"instruction":"Add ginger-garlic paste and capsicum. Cook 3 minutes."},{"order":4,"instruction":"Add tomatoes and cook until soft. Add pav bhaji masala and salt."},{"order":5,"instruction":"Add mashed vegetables. Mix and mash everything together on the griddle. Cook 10 minutes, adding water as needed."},{"order":6,"instruction":"Toast pav rolls with butter on the griddle. Serve bhaji topped with butter, chopped onion, and lemon juice."}]),"nutrition":j({"calories":380,"protein_g":9,"carbs_g":52,"fat_g":16,"serving_size":"1 serving"}),"tips":j(["The more you mash and cook the bhaji, the better it tastes.","Butter is not optional - it is the soul of pav bhaji.","Pav bhaji masala is a specific spice blend - do not substitute with garam masala.","A squeeze of lemon and raw onion on top is traditional and essential."]),"youtube_query":"pav bhaji recipe mumbai style","youtube_video_id":"Yw5UNqFBCow","prep_time":"15 minutes","cook_time":"30 minutes","total_time":"45 minutes","difficulty":"Easy","servings":"4 servings","related_recipes":j(["chole-bhature","samosa","pani-puri"]),"published":1})

# 28 Saag Aloo
recipes.append({"slug":"saag-aloo","version":1,"title":"Saag Aloo","category":"Indian","description":"Tender potatoes cooked with wilted spinach and mustard greens in a fragrant, spiced base. A hearty, wholesome North Indian vegetarian dish that pairs perfectly with roti.","hero_image_url":"https://images.unsplash.com/photo-1601050690597-df0568f70950?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixlib=rb-4.1.0&q=80&w=1080","meta_title":"Saag Aloo Recipe - Spiced Spinach and Potato Curry","meta_description":"Hearty saag aloo with tender potatoes and spiced spinach. Classic North Indian vegetarian dish ready in 30 minutes.","keywords":j(["saag aloo","spinach potato","indian vegetarian","saag recipe","north indian"]),"ingredients":j([{"name":"Potatoes","quantity":"400","unit":"g"},{"name":"Fresh spinach","quantity":"400","unit":"g"},{"name":"Onion","quantity":"1","unit":"large"},{"name":"Tomato","quantity":"1","unit":"medium"},{"name":"Ginger-garlic paste","quantity":"1","unit":"tbsp"},{"name":"Cumin seeds","quantity":"1","unit":"tsp"},{"name":"Turmeric","quantity":"0.5","unit":"tsp"},{"name":"Coriander powder","quantity":"1","unit":"tsp"},{"name":"Garam masala","quantity":"0.5","unit":"tsp"},{"name":"Oil","quantity":"3","unit":"tbsp"}]),"steps":j([{"order":1,"instruction":"Cut potatoes into cubes. Parboil for 5 minutes. Drain."},{"order":2,"instruction":"Heat oil. Add cumin seeds. Add onions and cook until golden."},{"order":3,"instruction":"Add ginger-garlic paste and tomato. Cook until soft."},{"order":4,"instruction":"Add turmeric, coriander powder, and salt. Add potatoes and stir to coat."},{"order":5,"instruction":"Add spinach in batches, stirring until wilted. Cover and cook 10 minutes."},{"order":6,"instruction":"Add garam masala. Serve with roti or naan."}]),"nutrition":j({"calories":240,"protein_g":6,"carbs_g":34,"fat_g":10,"serving_size":"1 serving"}),"tips":j(["Do not overcook the spinach - it should retain some texture.","Parboiling potatoes ensures they cook through without the spinach becoming mushy.","A squeeze of lemon at the end brightens the dish.","For a creamier version, add a tablespoon of cream at the end."]),"youtube_query":"saag aloo recipe spinach potato","youtube_video_id":"Yw5UNqFBCow","prep_time":"10 minutes","cook_time":"25 minutes","total_time":"35 minutes","difficulty":"Easy","servings":"4 servings","related_recipes":j(["palak-paneer","aloo-gobi","aloo-paratha"]),"published":1})

