# Generate SQL
def esc(s): return str(s).replace("'", "''")

lines = []
for r in recipes:
    sql = "INSERT OR REPLACE INTO recipes (\n  slug, version, title, category, description, hero_image_url,\n  meta_title, meta_description, keywords, ingredients, steps, nutrition,\n  tips, youtube_query, youtube_video_id, prep_time, cook_time, total_time,\n  difficulty, servings, related_recipes, published\n) VALUES (\n  '" + esc(r['slug']) + "', " + str(r['version']) + ", '" + esc(r['title']) + "', '" + esc(r['category']) + "',\n  '" + esc(r['description']) + "', '" + esc(r['hero_image_url']) + "',\n  '" + esc(r['meta_title']) + "', '" + esc(r['meta_description']) + "',\n  '" + esc(r['keywords']) + "', '" + esc(r['ingredients']) + "', '" + esc(r['steps']) + "', '" + esc(r['nutrition']) + "',\n  '" + esc(r['tips']) + "', '" + esc(r['youtube_query']) + "',\n  '" + esc(r.get('youtube_video_id','')) + "', '" + esc(r.get('prep_time','')) + "', '" + esc(r.get('cook_time','')) + "', '" + esc(r.get('total_time','')) + "',\n  '" + esc(r.get('difficulty','')) + "', '" + esc(r.get('servings','')) + "', '" + esc(r.get('related_recipes','[]')) + "', " + str(r['published']) + "\n);"
    lines.append(sql)

with open('fixchef/scripts/seed-indian-recipes.sql', 'w', encoding='utf-8') as f:
    f.write('\n'.join(lines) + '\n')
print(f'Wrote {len(lines)} INSERT statements to seed-indian-recipes.sql')
